mapper.select:
SELECT `s`.`index` AS `index`, `s`.`title` AS `title`, `st`.`display_text` AS `typeText`, `s`.`start_date` AS `startDate`, `s`.`end_date` AS `endDate`, 'schedules' AS `calendarType` FROM `wh`.`schedules` AS `s` LEFT JOIN `wh`.`schedule_states` AS `st` ON `s`.`state` = `st`.`code` LEFT JOIN `wh`.`schedule_members` AS `sm` ON `s`.`index` = `sm`.`schedule_index` LEFT JOIN `wh`.`users` AS `u` ON `sm`.`member_id` = `u`.`emp_id`
`u`.`team_code` = #{teamCode}
`sm`.`member_id` = #{empId}
GROUP BY `s`.`index`, `s`.`title`, `st`.`display_text`, `s`.`start_date`, `s`.`end_date` ORDER BY `s`.`start_date` ASC
